res = divmod(11, 3)
print(res) # 3, 2 (몫, 나머지)
print(abs(-5)) #절대값
print(pow(4, 2)) # 4의 2제곱
print(max(19, 30,  5)) # 최대값
print(min(10, 30, 5)) # 최소값
print(round(23.89)) # 반올림


import math
from math import * # math 모든 함수를 네임스페이스로 가져옴
print(math.floor(24.9)) # 내림
print(math.ceil(24.2)) # 올림
print(math.sqrt(16)) # 제곱근
print(math.factorial(5)) # 팩토리얼
print(math.pi) # 원주율
 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   